import{_ as e,c as i,a2 as r,o as t}from"./chunks/framework.YPpNXepj.js";const p=JSON.parse('{"title":"文件格式和扩展名","description":"","frontmatter":{},"headers":[],"relativePath":"计算机/文件.md","filePath":"计算机/文件.md","lastUpdated":null}'),a={name:"计算机/文件.md"};function o(n,l,s,c,d,h){return t(),i("div",null,l[0]||(l[0]=[r('<h1 id="文件格式和扩展名" tabindex="-1">文件格式和扩展名 <a class="header-anchor" href="#文件格式和扩展名" aria-label="Permalink to &quot;文件格式和扩展名&quot;">​</a></h1><ul><li>根据文件存储的信息类型, 粗略分为两类 <ul><li>纯文本文件: 人类可读的字符数据, 通过文本编辑器查看和编辑</li><li>二进制文件: 需要特定程序或工具解析和处理, 图像,音频,视频,可执行文件等等</li></ul></li><li>扩展名虽然指示文件类型或格式, 并不能决定文件本质的内容和信息. <ul><li>告诉操作系统, 文件的默认打开方式, 关联文件和特定的应用程序</li><li>帮助用户分类和管理文件</li><li>手动更改扩展名并不影响文件内容</li></ul></li><li>软件程序真正识别文件内容的方式: 文件头和文件尾, 而不是扩展名.</li><li>单一功能的软件只能识别特定类型的文件头尾, 对于存储了多类型信息的文件, 有时可以读取其中的部分内容, 例如: <ul><li>用音乐播放器打开视频文件</li><li>用解压缩软件打开PPT</li></ul></li><li><strong>纯文本文件没有文件头尾</strong>, 因此不包含任何格式信息</li></ul><h2 id="文件编码格式" tabindex="-1">文件编码格式 <a class="header-anchor" href="#文件编码格式" aria-label="Permalink to &quot;文件编码格式&quot;">​</a></h2><ul><li>所有文件都是用 0 1 机器码以字节为单位存储, 编码格式决定了字符与字节之间的映射关系</li><li>常见的编码格式: ASCII, UTF-8, UTF-16, GBK</li><li>Macintosh(CR)和Windows(CRLF)</li><li><a href="https://learn.microsoft.com/zh-cn/powershell/scripting/dev-cross-plat/vscode/understanding-file-encoding?view=powershell-7.4" target="_blank" rel="noreferrer">了解 VS Code 和 PowerShell 中的文件编码 - PowerShell | Microsoft Learn</a></li><li><a href="https://cloud.tencent.com/developer/article/2075577" target="_blank" rel="noreferrer">powershell重定向文本文件时注意显性指定编码-腾讯云开发者社区-腾讯云 (tencent.com)</a></li></ul>',4)]))}const f=e(a,[["render",o]]);export{p as __pageData,f as default};
